import os
from openai import OpenAI

def create_chatbot():
    api_key = os.environ.get('OPENAI_API_KEY')
    if not api_key:
        raise ValueError("OPENAI_API_KEY environment variable is not set")
    
    client = OpenAI(api_key=api_key)
    return client

def get_system_instructions():
    return """You are a helpful customer support assistant. 
You should be polite, professional, and provide accurate information to help customers with their inquiries.
Always maintain a friendly tone and ask clarifying questions when needed."""

def chat(client, user_message, conversation_history=None):
    if conversation_history is None:
        conversation_history = []
    
    if not user_message or not isinstance(user_message, str):
        raise ValueError("User message must be a non-empty string")
    
    user_message = user_message.strip()
    if len(user_message) > 4000:
        raise ValueError("User message is too long. Please limit to 4000 characters.")
    
    if not conversation_history:
        messages = [
            {"role": "system", "content": get_system_instructions()},
            {"role": "user", "content": user_message}
        ]
    else:
        messages = conversation_history + [{"role": "user", "content": user_message}]
    
    try:
        response = client.chat.completions.create(
            model="gpt-3.5-turbo",
            messages=messages,
            max_tokens=500,
            temperature=0.7
        )
        
        assistant_message = response.choices[0].message.content
        
        messages.append({"role": "assistant", "content": assistant_message})
        
        return assistant_message, messages
    
    except Exception as e:
        raise Exception(f"Error communicating with OpenAI API: {str(e)}")

def main():
    try:
        client = create_chatbot()
        print("Customer Support Chatbot")
        print("Type 'quit' or 'exit' to end the conversation\n")
        
        conversation_history = [{"role": "system", "content": get_system_instructions()}]
        
        while True:
            user_input = input("You: ").strip()
            
            if user_input.lower() in ['quit', 'exit']:
                print("Thank you for contacting customer support. Goodbye!")
                break
            
            if not user_input:
                print("Please enter a message.")
                continue
            
            try:
                response, conversation_history = chat(client, user_input, conversation_history)
                print(f"\nAssistant: {response}\n")
            except ValueError as ve:
                print(f"Input error: {str(ve)}")
            except Exception as e:
                print(f"Error: {str(e)}")
                break
    
    except ValueError as ve:
        print(f"Configuration error: {str(ve)}")
    except Exception as e:
        print(f"Unexpected error: {str(e)}")

if __name__ == "__main__":
    main()